var sync_uuid = (Date.now().toString(36).toUpperCase().slice(-4) + Math.random().toString(36).substring(2,6).toUpperCase() + Math.random().toString(36).substring(2,6).toUpperCase());
msg.sync_uuid = sync_uuid;

var q = ""
+ "SELECT TOP 300\n"
+ "    COD_CLIENTE AS CODIGO,\n"
+ "    NOM_CLIENTE AS PROVEEDOR,\n"
+ "    DESCRIPCION AS COMPROBANTE,\n"
+ "    SUBSTRING(FECHAEMISION, 1, 8) AS FECHA,\n"
+ "    SUBSTRING(FECHAVENCIMIENTO, 1, 8) AS VENCIMIENTO,\n"
+ "    ISNULL(SALDO, 0) AS IMPORTE,\n"
+ "    ISNULL(UN, '') AS UNIDAD_NEGOCIO\n"
+ "FROM V_EZI_PROV_FAC_PEND\n"
+ "WHERE SALDO > 0\n"
+ "ORDER BY VENCIMIENTO ASC;\n";

msg.payload = q;
node.warn('[Sync-PP] Preparando sync ' + sync_uuid);
return msg;

var rows = msg.payload;
var sync_uuid = msg.sync_uuid || 'N/A';
var timestamp = new Date().toISOString();
msg._syncInfo = { sync_uuid: sync_uuid, timestamp: timestamp };
if (!rows || !Array.isArray(rows) || rows.length === 0) {
  node.warn('[Sync-PP] Sin datos.'); msg._syncInfo.empty = true; msg.payload = null; return msg;
}
// Calcular DIAS para cada documento
var now = new Date();
var today = now.getFullYear() + String(now.getMonth() + 1).padStart(2, '0') + String(now.getDate()).padStart(2, '0');

// Columnas A-I: PROVEEDOR|COMPROBANTE|FECHA|VENCIMIENTO|DIAS|IMPORTE|ESTADO|UNIDAD_NEGOCIO|SYNC_UUID
var data = [];
for (var i = 0; i < rows.length; i++) {
  var r = rows[i]; if (!r) continue;
  var venc = (r.VENCIMIENTO || '').toString().trim();
  var importe = parseFloat(r.IMPORTE) || 0; if (importe === 0) continue;

  var dias = 0;
  if (venc.length >= 8) {
    var vYear = parseInt(venc.substring(0,4), 10);
    var vMonth = parseInt(venc.substring(4,6), 10) - 1;
    var vDay = parseInt(venc.substring(6,8), 10);
    var vDate = new Date(vYear, vMonth, vDay);
    var tDate = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    dias = Math.floor((tDate - vDate) / (1000 * 60 * 60 * 24));
  }
  var estado = dias > 0 ? 'VENCIDO' : (dias >= -7 ? 'A_VENCER' : 'VIGENTE');

  data.push([
    (r.PROVEEDOR || '').toString().trim(),
    (r.COMPROBANTE || '').toString().trim(),
    (r.FECHA || '').toString().trim(),
    venc,
    dias,
    importe,
    estado,
    (r.UNIDAD_NEGOCIO || '').toString().trim(),
    sync_uuid
  ]);
}
// Ordenar: vencidos primero
data.sort(function(a,b){ return (b[4]||0) - (a[4]||0); });

msg._sheetData = data; msg.payload = data;
msg._syncInfo.rowCount = data.length;
node.warn('[Sync-PP] ' + data.length + ' pendientes. UUID=' + sync_uuid);
return msg;

// El GSheet Clear sobreescribe msg.payload con la respuesta de la API
// Restaurar el array 2D desde _sheetData para que el Append funcione
if (msg._sheetData) {
  msg.payload = msg._sheetData;
}
return msg;

var info = msg._syncInfo || {};
if (info.empty) {
  node.warn('[Sync-pp] Sync omitido: sin datos');
  return msg;
}
if (msg.error) {
  node.error('[Sync-pp] ERROR: ' + msg.error);
  return msg;
}
var updatedRange = '';
if (msg.payload && msg.payload.updates) updatedRange = msg.payload.updates.updatedRange || '';
node.warn('[Sync-pp] ✅ Sync exitoso — ' + (info.rowCount || 0) + ' filas → ProveedoresPendientes');
node.warn('[Sync-pp]    UUID: ' + (info.sync_uuid || '?') + ' | Rango: ' + updatedRange);
return msg;
